class Solution {
public:
    vector<int> maxDepthAfterSplit(string seq) {
        vector<int> ans(seq.size());
        int depth = 0;
        for (int i = 0; i < seq.size(); ++i) {
            if (seq[i] == '(') {
                ++depth;
                ans[i] = depth & 1;
            } else {
                ans[i] = depth & 1;
                --depth;
            }
        }
        return ans;
    }
};
```
